def main():
    n = int(input())
    a = list(input())
    b = [0] * n
    for i in range(n):
        if a[i] == 'B':
            b[i] = 1
    ans = []
    for i in range(n):
        if b[i] == 1:
            j = i
            while j < n and b[j] == 1:
                j += 1
            ans.append(j - i)
            i = j
    print(len(ans))
    print(*ans)


if __name__ == '__main__':
    main()
